using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Look up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxRetries', 'Timeout')")] string key)
    {
        var config = AppConfig.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Update a configuration value. Returns the new state.")]
    public static string SetConfigValue(
        [Description("The configuration key to set")] string key,
        [Description("The new value")] string value)
    {
        AppConfig.Current[key] = value;
        return $"Updated {key} = {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "Application Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings() =>
        JsonSerializer.Serialize(AppConfig.Current, AppConfig.JsonOptions);

    [McpServerResource(
        UriTemplate = "config://app/environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironmentInfo() =>
        JsonSerializer.Serialize(new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessId = Environment.ProcessId,
            StartTime = DateTime.UtcNow
        }, AppConfig.JsonOptions);
}

using System.Collections.Concurrent;
using System.Text.Json;

public static class AppConfig
{
    public static readonly ConcurrentDictionary<string, string> Current = new(
        new Dictionary<string, string>
        {
            ["MaxRetries"] = "3",
            ["Timeout"] = "30s",
            ["LogLevel"] = "Information",
            ["FeatureFlags"] = "dark-mode,beta-api"
        });

    public static readonly JsonSerializerOptions JsonOptions = new()
    {
        WriteIndented = true
    };
}

