using ModelContextProtocol.Server;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddMcpServer(options =>
{
    options.ServerInfo = new() { Name = "ConfigMcpServer", Version = "1.0.0" };
    options.ServerInstructions = "Manage and inspect application configuration. "
        + "Use tools to get/set config values. Read resources for full config snapshots.";
})
.WithHttpTransport()
.WithToolsFromAssembly()
.WithResourcesFromAssembly();

var app = builder.Build();

app.MapMcp();
app.MapGet("/health", () => "ok");

app.Run();

